  ('optician-moex-01177', 'optician', 'optician-moex-109-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '關於配戴硬式隱形眼鏡時，鏡片與角膜之間的淚水所產生的淚膜層鏡片效應（tearlenseffect）的敘述，下 列何者錯誤？', '["鏡片與角膜之間的淚水所產生的淚膜層鏡片效應與鏡片後表面弧度及角膜前表面弧度有關", "當鏡片後表面弧度等於角膜前表面弧度時，鏡片與角膜之間的淚水所產生的淚膜層鏡片效應未產生凹 凸透鏡的效果", "當鏡片後表面的曲率半徑小於角膜前表面曲率半徑時，鏡片與角膜之間的淚水所產生的淚膜層鏡片效 應等同凹透鏡的效果", "鏡片與角膜之間的淚水所產生的淚膜層鏡片效應與鏡片前表面弧度無絕對直接關聯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "2c4b746a8041", "answer_pdf_sha1": "f613faae0374", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
